import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Trovare Mod Affidabili","description":"Una guida su come trovare mod Fabric attraverso fonti affidabili.","frontmatter":{"title":"Trovare Mod Affidabili","description":"Una guida su come trovare mod Fabric attraverso fonti affidabili.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"it_it/1.21.8/players/finding-mods.md","filePath":"versions/1.21.8/translated/it_it/players/finding-mods.md","lastUpdated":1760721669000}`);var a={name:`it_it/1.21.8/players/finding-mods.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Trovare Mod Affidabili <a class="header-anchor" href="#h1" aria-label="Permalink to “Trovare Mod Affidabili”">​</a></h1><p>Anzitutto, la fiducia è soggettiva, e dovresti sempre affidarti al tuo giudizio quando scarichi mod. Tuttavia, ci sono alcune cose che puoi fare che ti aiutano a trovare mod affidabili.</p><h2 id="trustworthy-source" tabindex="-1">1. Usa una Fonte Nota per Essere Affidabile <a class="header-anchor" href="#trustworthy-source" aria-label="Permalink to “1. Usa una Fonte Nota per Essere Affidabile”">​</a></h2><p>La maggior parte degli autori pubblica le loro mod su <a href="https://modrinth.com/mods?g=categories:%27fabric%27" target="_blank" rel="noreferrer">Modrinth</a> e CurseForge.</p><p>Questi siti controllano che le mod siano quello che dicono di essere, e che non contengano codice maligno. Puoi anche segnalare mod sospette su quei siti, ed essi agiranno in modo relativamente veloce.</p><h2 id="with-others" tabindex="-1">2. Controlla con gli Altri! <a class="header-anchor" href="#with-others" aria-label="Permalink to “2. Controlla con gli Altri!”">​</a></h2><p>Se stai scaricando una mod da una fonte che non è nota per essere affidabile, dovresti controllare con gli altri per vedere se loro l&#39;hanno scaricata prima dalla posizione da cui la stai scaricando tu, e se hanno avuto problemi con essa.</p><p>Se hai dubbi, sentiti libero di chiedere nel <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord di Fabric</a> nel canale <code>#player-support</code>.</p><h2 id="avoid-malware" tabindex="-1">3. Evita Siti Comuni Maligni! <a class="header-anchor" href="#avoid-malware" aria-label="Permalink to “3. Evita Siti Comuni Maligni!”">​</a></h2><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>I siti maligni potrebbero non essere ovvi per tutti. Se non sei sicuro, dovresti chiedere l&#39;opinione di altri o evitare il sito completamente e affidarti solo a fonti fidate, come Modrinth e CurseForge.</p></div><p>Ci sono tanti siti che dicono di avere mod per Minecraft, ma che sono in realtà solo siti maligni. Dovresti evitare questi siti a tutti i costi.</p><p>Puoi usare software antivirus e siti come <a href="https://www.microsoft.com/it-it/windows/comprehensive-security" target="_blank" rel="noreferrer">Windows Defender</a> o <a href="https://www.virustotal.com/" target="_blank" rel="noreferrer">VirusTotal</a> per controllare le mod scaricate. Tuttavia, non affidarti completamente su quei metodi, perché a volte potrebbero essere errati.</p><p>Ancora, se hai dubbi, sentiti libero di chiedere l&#39;opinione di altri nel <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord di Fabric</a> nel canale <code>#player-support</code>.</p>`,13)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};